import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrentGeneration {
  power: number;
  unit: string;
}

interface DailyYield {
  hour: string;
  yield: number;
}

interface MonthlySavings {
  amount: number;
  currency: string;
}

interface SolarData {
  currentGeneration: CurrentGeneration;
  dailyYield: DailyYield[];
  monthlySavings: MonthlySavings;
}

export default function Widget() {
  const solarData = response.data as SolarData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FFD700' }}>
              Current Generation
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF8C00' }}>
              {solarData.currentGeneration.power} {solarData.currentGeneration.unit}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Power Output
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: solarData.dailyYield.map(d => d.yield),
                  color: '#FFD700',
                  label: 'Yield',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: solarData.dailyYield.map(d => d.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'yield' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="yield"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FF8C00', fontWeight: 600 }}>
              Monthly Savings
            </Typography>
            <Typography variant="h5" fontWeight={700} sx={{ color: '#FFD700' }}>
              {solarData.monthlySavings.currency}{solarData.monthlySavings.amount.toFixed(2)}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
